// Aliases and Regen icons mapping
ICONS.total_as = ICONS.attack_speed;
ICONS.energyregen_mod = ICONS.mana_regen;
ICONS.manaregen_mod = ICONS.mana_regen;
ICONS.energy_regen = ICONS.mana_regen;

const DISPLAY_ORDER = ['dmg_dealt', 'dmg_taken', 'healing', 'shielding', 'attack_speed', 'total_as', 'ability_haste', 'movement_speed', 'tenacity', 'crit_mod', 'energyregen_mod', 'manaregen_mod'];

function buildStatsHtml(stats) {
    const entries = [];
    for (const key of DISPLAY_ORDER) {
        const val = stats[key];
        if (typeof val === 'number') {
            if (key === 'ability_haste' && val === 0) continue;
            if (key !== 'ability_haste' && val === 1.0) continue;
            entries.push([key, val]);
        }
    }
    
    if (entries.length === 0) {
        return '<div style="color:#746e64;font-style:italic;font-size:12px;margin-top:4px;">No balance adjustments</div>';
    }
    
    return entries.map(([key, value]) => {
      const label = LABELS[key] ?? key;
      const iconSvg = ICONS[key] || ICONS['dmg_dealt'];
      
      let isBuff = false;
      let displayValue = '';

      if (key === 'ability_haste') {
          isBuff = value > 0;
          displayValue = (value > 0 ? '+' : '') + value;
      } else {
          const percentChange = (value - 1.0) * 100;
          if (key === 'dmg_taken') {
              isBuff = value < 1.0;
          } else {
              isBuff = value > 1.0;
          }
          displayValue = (percentChange >= 0 ? '+' : '') + percentChange.toFixed(1) + '%';
      }

      const color = isBuff ? '#5bbd72' : '#e84749';
      const icon = `<div style="width:18px; height:18px; margin-right:10px; display:inline-flex; align-items:center; opacity:0.9;">${iconSvg}</div>`;
      
      return `
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px; font-size:13px; color:#a09b8c;">
            <div style="display:flex; align-items:center;">
                ${icon}
                <span>${label}</span>
            </div>
            <span style="color:${color}; font-weight:bold; font-family:var(--font-body); margin-left:24px;">${displayValue}</span>
        </div>`;
    }).join('');
}

let ttRoot = null, ttCaption = null, ttContent = null;
  
function createCustomTooltip() {
    if (ttRoot) return;
    ttRoot = document.createElement('div');
    ttRoot.style.cssText = 'position:fixed; z-index:19001; background:#1a1c21; border:1px solid #785a28; border-radius:2px; pointer-events:none; opacity:0; transition:opacity 0.1s; box-shadow:0 0 12px rgba(0,0,0,0.8); min-width:240px;';
    const body = document.createElement('div');
    body.style.cssText = 'padding:16px 20px;';
    ttCaption = document.createElement('div');
    ttCaption.style.cssText = 'color:#f0e6d2; font-size:15px; font-weight:bold; letter-spacing:.075em; line-height:20px; text-transform:uppercase; margin-bottom:12px; border-bottom:1px solid #3e2e13; padding-bottom:8px;';
    ttContent = document.createElement('div');
    ttContent.style.cssText = 'display:flex; flex-direction:column;';
    body.appendChild(ttCaption);
    body.appendChild(ttContent);
    ttRoot.appendChild(body);
    document.body.appendChild(ttRoot);
}

function showTT(anchor, position, caption, html) {
    if (!ttRoot) createCustomTooltip();
    ttCaption.textContent = caption;
    ttContent.innerHTML = html;
    const rect = anchor.getBoundingClientRect();
    let left = position === 'bottom' ? rect.left + (rect.width / 2) - 120 : rect.right + 12;
    let top = position === 'bottom' ? rect.bottom + 8 : rect.top + (rect.height / 2) - 80;
    if (left + 260 > window.innerWidth) left = window.innerWidth - 268;
    if (top + 200 > window.innerHeight) top = window.innerHeight - 208;
    if (left < 8) left = 8;
    if (top < 8) top = 8;
    ttRoot.style.left = left + 'px';
    ttRoot.style.top = top + 'px';
    ttRoot.style.opacity = '1';
}

function hideTT() { 
    if (ttRoot && ttRoot.style.opacity !== '0') ttRoot.style.opacity = '0'; 
}

function showBalanceTooltip(component, position) {
    if (!isEnabled || !currentMode || Object.keys(balanceData).length === 0) {
        hideTT();
        return;
    }
    
    // Extract the champion ID directly from whichever Ember model is present
    const champId = component.get('champion.id') 
        || component.get('summoner.championId') 
        || component.get('championConfiguration.champion.id') 
        || component.get('championId');
        
    if (!champId) {
        hideTT();
        return;
    }
    
    const stats = balanceData[champId]?.stats?.[currentMode] || {};
    showTT(component.element, position, `${currentMode.toUpperCase()} BALANCE`, buildStatsHtml(stats));
}

function parseStatsBlock(content) {
    const stats = {};
    const modes = ['aram', 'ar', 'nb', 'ofa', 'urf', 'usb'];
    const keyRegex = /\["([^"]+)"\]\s*=\s*(-?\d+\.?\d*)/g;
    modes.forEach(mode => {
        const modeStartIdx = content.indexOf(`["${mode}"] = {`);
        if (modeStartIdx === -1) return;
        let balance = 0;
        let modeEndIdx = -1;
        const startSearch = modeStartIdx + `["${mode}"] = `.length;
        for (let j = startSearch; j < content.length; j++) {
            if (content[j] === '{') balance++;
            else if (content[j] === '}') {
                balance--;
                if (balance === 0) {
                    modeEndIdx = j + 1;
                    break;
                }
            }
        }
        if (modeEndIdx !== -1) {
            const modeContent = content.substring(modeStartIdx, modeEndIdx);
            stats[mode] = {};
            let m;
            const localKeyRegex = new RegExp(keyRegex);
            while ((m = localKeyRegex.exec(modeContent)) !== null) {
                stats[mode][m[1]] = parseFloat(m[2]);
            }
        }
    });
    return stats;
}

async function fetchWikiData() {
    try {
        Utils.Debug.log('[Snooze-Balance] Fetching real-time Lua data from League Wiki...');
        const res = await fetch('https://wiki.leagueoflegends.com/en-us/Module:ChampionData/data?action=raw');
        if (!res.ok) throw new Error('Wiki fetch failed');
        const lua = await res.text();
        const data = {};
        const champRegex = /^\s*\["(.+?)"\] = \{/gm;
        let match;
        while ((match = champRegex.exec(lua)) !== null) {
            const name = match[1];
            const startIdx = match.index;
            let balance = 0;
            let endIdx = -1;
            const searchFrom = startIdx + `["${name}"] = `.length;
            for (let j = searchFrom; j < lua.length; j++) {
                if (lua[j] === '{') balance++;
                else if (lua[j] === '}') {
                    balance--;
                    if (balance === 0) {
                        endIdx = j + 1;
                        break;
                    }
                }
            }
            if (endIdx !== -1) {
                const entryContent = lua.substring(startIdx, endIdx);
                const idMatch = entryContent.match(/\["id"\]\s*=\s*(\d+)/);
                if (idMatch) {
                    const id = idMatch[1];
                    const statsMarker = '["stats"] = {';
                    const statsStartIdx = entryContent.indexOf(statsMarker);
                    if (statsStartIdx !== -1) {
                        let sBalance = 0;
                        let statsEndIdx = -1;
                        for (let k = statsStartIdx + '["stats"] = '.length; k < entryContent.length; k++) {
                            if (entryContent[k] === '{') sBalance++;
                            else if (entryContent[k] === '}') {
                                sBalance--;
                                if (sBalance === 0) {
                                    statsEndIdx = k + 1;
                                    break;
                                }
                            }
                        }
                        if (statsEndIdx !== -1) {
                            const statsBlock = entryContent.substring(statsStartIdx, statsEndIdx);
                            data[id] = { name, stats: parseStatsBlock(statsBlock) };
                        }
                    }
                }
            }
            if (champRegex.lastIndex === startIdx) champRegex.lastIndex++;
        }
        if (Object.keys(data).length > 0) {
            balanceData = data;
            Utils.Debug.log('[Snooze-Balance] Successfully parsed Wiki data for', Object.keys(data).length, 'champions.');
        }
    } catch (e) {
        Utils.Debug.error('[Snooze-Balance] Wiki processing failed:', e);
    }
}

async function syncMode() {
    if (!Utils.LCU) return;
    const session = await Utils.LCU.get('/lol-gameflow/v1/session');
    const rawMode = session?.gameData?.queue?.gameMode;
    currentMode = getModeKey(rawMode);
}

async function handleGameflowPhase(phase) {
    if (phase === 'ChampSelect' && isEnabled) {
        try {
            await syncMode();
        } catch (e) {
            currentMode = null;
        }
    } else {
        currentMode = null;
    }
    hideTT();
}

function activateIfChampSelect() {
    if (!Utils.LCU || !Utils.LCU.get) return;
    Utils.LCU.get('/lol-gameflow/v1/gameflow-phase')
        .then(handleGameflowPhase)
        .catch(() => {});
}

function mountSnoozeBalanceTooltip() {
    if (Utils.LCU && Utils.LCU.observe && !balancePhaseUnsub) {
        balancePhaseUnsub = Utils.LCU.observe('/lol-gameflow/v1/gameflow-phase', e => handleGameflowPhase(e.data));
        activateIfChampSelect();
    }
}

function unmountSnoozeBalanceTooltip() {
    if (balancePhaseUnsub) {
        balancePhaseUnsub();
        balancePhaseUnsub = null;
    }
    currentMode = null;
    hideTT();
}

export function init(context) {
    Utils.Settings.inject(context, {
        name: "balance-tooltip-settings",
        titleKey: "snooze_balance-tooltip",
        titleName: "Balance Tooltip",
        capitalTitleKey: "snooze_balance-tooltip_capital",
        capitalTitleName: "BALANCE TOOLTIP",
        class: "balance-tooltip-settings"
    });
    isEnabled = Utils.Store.get('SnoozeBalanceTooltip', 'enabled') || false;

    // Register hover rules for all target Champion Select Ember components
    HOVER_COMPONENTS.forEach(r => {
        Utils.Hooks.Ember.registerRule({
            name: `balance-tooltip-${r.name}-hook`,
            matcher: r.name,
            mixin() {
                return {
                    didInsertElement() {
                        if (typeof this._super === 'function') {
                            this._super(...arguments);
                        }
                        if (!this.element) return;
                        
                        this.element.addEventListener('mouseenter', () => {
                            showBalanceTooltip(this, r.pos);
                        });
                        this.element.addEventListener('mouseleave', () => {
                            hideTT();
                        });
                    },
                    willDestroyElement() {
                        hideTT();
                        if (typeof this._super === 'function') {
                            this._super(...arguments);
                        }
                    }
                };
            }
        });
    });

    if (window.SnoozeManager && window.SnoozeManager.registerModule) {
        window.SnoozeManager.registerModule({
            id: 'SnoozeBalanceTooltip',
            name: 'Balance Tooltip',
            description: 'Hover over champions in special modes (ARAM/URF/Arena) to see balance info/nerfs natively.',
            settings: [
                {
                    type: 'toggle',
                    id: 'sm:SnoozeBalanceTooltip',
                    label: 'Enable Balance Tooltip',
                    description: 'Shows per-mode stat buffs and nerfs when you hover a champion in champ select',
                    value: isEnabled,
                    onChange: (val) => toggleFeature(val)
                }
            ]
        });
    } else {
        Utils.DOM.observer.observe("lol-uikit-scrollable.balance-tooltip-settings", (plugin) => {
            plugin.innerHTML = '';
            plugin.appendChild(Utils.Settings.createToggleRow("Enable Balance Tooltip", isEnabled, (next) => {
                isEnabled = next;
                Utils.Store.set('SnoozeBalanceTooltip', 'enabled', isEnabled);
                toggleFeature(isEnabled);
            }));
        });
    }
}

export function load() {
    fetchWikiData();
    if (isEnabled) mountSnoozeBalanceTooltip();
}